import { task } from "@trigger.dev/sdk";

// Sub-task that returns a success result
export const subTask1 = task({
  id: "sub-task-1",
  run: async ({ trialId }: { trialId: string }) => {
    console.log(`Running sub-task-1 for trial: ${trialId}`);

    // Return success result
    return { success: true };
  },
});

// Parent task that triggers and waits for the sub-task
export const parentTask = task({
  id: "parent-task",
  run: async ({ trialId }: { trialId: string }) => {
    console.log(`Running parent-task for trial: ${trialId}`);

    // Trigger the sub-task and wait for its completion
    const result = await subTask1.triggerAndWait({
      trialId,
    });

    // Unwrap the result
    const unwrappedResult = result.unwrap();

    console.log(`Sub-task result: ${JSON.stringify(unwrappedResult)}`);

    // Return the sub-task result
    return { subTaskResult: unwrappedResult };
  },
});

